const langResult = $('LangGraph Analyze').first().json;
const job_id = $('Insert row').first().json.job_id;

let imageAnalysis = '';
let imageUrls = '';

try {
  const img = $('Call Image Analyser').first().json;
  imageUrls = JSON.stringify(img.image_urls || []);
  imageAnalysis = img.room_type
    ? 'Room: ' + img.room_type + ' | Condition: ' + img.condition_score + '/1.0 | Confidence: ' + Math.round(img.confidence * 100) + '%'
    : '';
} catch (e) {}

let result;
if (langResult.status === 'incomplete') {
  result = langResult.clarification_message || 'Submission incomplete — missing fields: ' + (langResult.missing_fields || []).join(', ');
} else {
  const a = langResult.analysis || {};
  result = [
    '**Embassy Recommendation:** ' + (a.recommendation || 'N/A'),
    '',
    '**Market Context:** ' + (a.market_context || ''),
    '',
    '**Property Assessment:** ' + (a.property_assessment || ''),
    '',
    '**Pricing Opinion:** ' + (a.pricing_opinion || ''),
    '',
    '**Expected Timeline:** ' + (a.expected_timeline || ''),
  ].join('\n');
  if (imageAnalysis) {
    result += '\n\n**Image Analysis:** ' + imageAnalysis;
  }
}

return [{ json: {
  job_id,
  result,
  status: langResult.status,
  intent: langResult.intent,
  confidence: langResult.confidence || 0,
  recommendation: (langResult.analysis || {}).recommendation || 'PASS',
  image_urls: imageUrls,
  image_analysis: imageAnalysis,
} }];

const userItem  = $('User Submit').first();
const binary     = userItem.binary || {};
const jobId      = $('Insert row').first().json.job_id;
const actualKeys = Object.keys(binary).filter(k => k.startsWith('file')).sort();
const MAX_FILES  = 5;

// Pad slots so formBinaryData params never reference a missing key
const outBinary = {};
for (let i = 0; i < MAX_FILES; i++) {
  const src = actualKeys[Math.min(i, actualKeys.length - 1)];
  outBinary[`file${i}`] = binary[src];
}

return [{ json: { job_id: jobId, file_count: actualKeys.length }, binary: outBinary }];
